#!/bin/bash
# GrantFlow AI — Local Setup & GitHub Push Script
# Usage: bash setup_push.sh
set -e
PAT="${GITHUB_TOKEN:?Set GITHUB_TOKEN before running this script}"
REPO="https://${PAT}@github.com/kida256-glitch/GrantFlow-AI.git"

echo "🚀 GrantFlow AI — Creating files and pushing to GitHub..."
D=$(mktemp -d)
mkdir -p "$D/agent/resources/analyze-files" "$D/agent/resources/deeprag"
mkdir -p "$D/portal" "$D/data" "$D/docs" "$D/database"

put(){ echo "$2" | base64 -d > "$D/$1"; echo "  ✅ $1"; }
put 'README.md' ''
put 'ARCHITECTURE.md' ''
put 'DEMO_SCRIPT.md' ''
put 'SETUP_GUIDE.md' ''
# SKIP: /tmp/LICENSE
# SKIP: /tmp/DEPLOYMENT_GUIDE.md
# SKIP: /tmp/TEST_CASES.md
put 'agent/agent.json' ''
put 'agent/entry-points.json' ''
put 'agent/project.uiproj' ''
put 'agent/resources/analyze-files/resource.json' ''
put 'agent/resources/deeprag/resource.json' ''
put 'data/email_templates.json' ''
put 'data/sample_applicants.json' ''
put 'data/scholarship_database.json' ''
# SKIP: /tmp/portal/index.html
# SKIP: /tmp/portal/reviewer.html
# SKIP: /tmp/portal/admin.html
# SKIP: /tmp/portal/styles.css
# SKIP: /tmp/portal/app.js
# SKIP: /tmp/database/schema.sql
# SKIP: /tmp/docs/api-documentation.md
cd "$D"
git init -q
git config user.email "grantflow@hackathon.com"
git config user.name "GrantFlow AI"
git add .
git commit -q -m "feat: GrantFlow AI — UiPath AgentHack 2026 Submission

8-stage autonomous AI pipeline for scholarship processing
Powered by Claude Sonnet 4.6 + UiPath Agent Builder (Low-Code)
Track 1: UiPath Maestro Case"
git branch -M main
git remote add origin "$REPO"
git push -u origin main --force
echo ""
echo "✅ All files pushed!"
echo "🔗 https://github.com/kida256-glitch/GrantFlow-AI"
